
"use client";

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { UtensilsCrossed, KeyRound, Loader2 } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { getAdminPassword } from '@/ai/flows/config-flow';

export default function LoginPage() {
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [isCheckingPassword, setIsCheckingPassword] = useState(false);
  const [isAdminDialogOpen, setIsAdminDialogOpen] = useState(false);
  const router = useRouter();
  const { toast } = useToast();
  
  const handleUserLogin = () => {
    if (!name.trim()) {
      toast({
        variant: "destructive",
        title: "輸入錯誤",
        description: "請輸入您的暱稱以開始訂餐。",
      });
      return;
    }
    router.push(`/order?username=${encodeURIComponent(name)}`);
  };

  const handleAdminLogin = async () => {
    if (!password) {
        toast({
            variant: "destructive",
            title: "輸入錯誤",
            description: "請輸入管理者密碼。",
        });
        return;
    }
    setIsCheckingPassword(true);
    try {
        const correctPassword = await getAdminPassword();
        if (password === correctPassword) {
            toast({ title: "管理者登入成功" });
            setIsAdminDialogOpen(false);
            router.push('/admin');
        } else {
            toast({
                variant: "destructive",
                title: "密碼錯誤",
                description: "請檢查您的管理者密碼。",
            });
        }
    } catch (error) {
        toast({
            variant: "destructive",
            title: "登入失敗",
            description: error instanceof Error ? error.message : "無法驗證管理者密碼",
        });
    } finally {
        setIsCheckingPassword(false);
        setPassword('');
    }
  };

  const handleUserKeyPress = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      handleUserLogin();
    }
  };
  
  const handleAdminKeyPress = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      handleAdminLogin();
    }
  };

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-background p-4">
      <div className="w-full max-w-sm">
        <Card className="shadow-2xl">
          <CardHeader className="text-center">
            <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-primary/10">
                <UtensilsCrossed className="h-8 w-8 text-primary" />
            </div>
            <CardTitle className="font-headline text-3xl">餓了嗎？</CardTitle>
            <CardDescription>日常的飢餓管理中心</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <Input
              id="name"
              type="text"
              placeholder="請輸入您的暱稱"
              value={name}
              onChange={(e) => setName(e.target.value)}
              onKeyPress={handleUserKeyPress}
              className="h-12 text-center text-lg"
            />
          </CardContent>
          <CardFooter>
            <Button onClick={handleUserLogin} className="w-full text-base py-6 bg-accent text-accent-foreground hover:bg-accent/90">
              開始點餐
            </Button>
          </CardFooter>
        </Card>
        <div className="mt-4 text-center">
            <Dialog open={isAdminDialogOpen} onOpenChange={setIsAdminDialogOpen}>
                <DialogTrigger asChild>
                    <Button variant="link" className="text-muted-foreground text-xs">管理者登入</Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-[425px]">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <KeyRound className="h-5 w-5" />
                            管理者登入
                        </DialogTitle>
                        <DialogDescription>
                            請輸入管理者密碼以進入後台管理介面。
                        </DialogDescription>
                    </DialogHeader>
                    <div className="grid gap-4 py-4">
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="password" className="text-right">
                                密碼
                            </Label>
                            <Input
                                id="password"
                                type="password"
                                className="col-span-3"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                onKeyPress={handleAdminKeyPress}
                                disabled={isCheckingPassword}
                            />
                        </div>
                    </div>
                    <DialogFooter>
                        <Button type="button" onClick={handleAdminLogin} disabled={isCheckingPassword}>
                            {isCheckingPassword && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            登入
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
      </div>
    </div>
  );
}
